/**
 * MedX errors forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Error message mapping and i18n keys.
 */
const ERRORS_TOKENS = Object.freeze({
  primary: { value: "forms-errors-primary", scope: "forms" },
  secondary: { value: "forms-errors-secondary", scope: "forms" },
  muted: { value: "forms-errors-muted", scope: "forms" },
  accent: { value: "forms-errors-accent", scope: "forms" },
  surface: { value: "forms-errors-surface", scope: "forms" },
});

const ERRORS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const ERRORS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const errorsRegistry = new Map();
const ERRORS_listeners = new Set();
let ERRORS_seq = 0;

function createErrorsId(prefix = "medx-forms-errors") {
  ERRORS_seq += 1;
  return `${prefix}-${ERRORS_seq}`;
}

function registerErrors(config = {}) {
  const entryId = config.id ?? createErrorsId();
  const preset = ERRORS_PRESETS[config.preset ?? "default"] ?? ERRORS_PRESETS.default;
  const token = ERRORS_TOKENS[config.token ?? preset.token] ?? ERRORS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: ERRORS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  errorsRegistry.set(entryId, entry);
  notifyErrorsListeners("register", entry);
  return entry;
}

function updateErrors(id, patch = {}) {
  const entry = errorsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyErrorsListeners("update", entry);
  return entry;
}

function resolveErrors(id) {
  const entry = errorsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listErrorsEntries(filter = {}) {
  let items = Array.from(errorsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onErrorsEvent(listener) {
  ERRORS_listeners.add(listener);
  return () => ERRORS_listeners.delete(listener);
}

function notifyErrorsListeners(type, entry) {
  for (const listener of ERRORS_listeners) {
    try {
      listener({ type, entry, registrySize: errorsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:errors] listener error", err.message);
    }
  }
}

function getErrorsMetrics() {
  const items = listErrorsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(ERRORS_TOKENS).length,
    presets: Object.keys(ERRORS_PRESETS).length,
  };
}

async function runMedxErrors() {
  console.log("[medx:ui:forms:errors] runtime initialized");
  console.log(`[medx:ui:forms:errors] tokens=${Object.keys(ERRORS_TOKENS).length} presets=${Object.keys(ERRORS_PRESETS).length}`);

  const events = [];
  onErrorsEvent((e) => events.push(e.type));

  const domains = Object.keys(ERRORS_SUPPLY_CHAIN);
  const presets = Object.keys(ERRORS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerErrors({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/errors" },
    });
  }

  const first = listErrorsEntries()[0];
  if (first) updateErrors(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getErrorsMetrics();
  const resolved = first ? resolveErrors(first.id) : null;

  console.log(`[medx:ui:forms:errors] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:errors] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:errors] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:errors] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:errors] bootstrap complete");
}

module.exports = runMedxErrors;
